import './styles/App.css';
import Header from './pages/Header';
import Main from './pages/Main';
import Footer from './pages/Footer';
import {Route,Routes} from "react-router-dom"

function App() {
  return (
    <div className="App">
      <Header />
      <Routes>
        <Route path="/home" element={<Main />} />
      </Routes>
      <Footer />
    </div>
  );
}

export default App;
